#!/usr/bin/env node
// minimal-mcp.js — reads JSON-RPC from stdin, writes responses to stdout
const readline = require('readline');

const rl = readline.createInterface({ input: process.stdin });

const TOOLS = [
  {
    name: 'get_timestamp',
    description: 'Returns the current UTC timestamp as an ISO 8601 string.',
    inputSchema: { type: 'object', properties: {}, required: [] }
  }
];

function send(obj) {
  process.stdout.write(JSON.stringify(obj) + '\n');
}

rl.on('line', (line) => {
  let msg;
  try { msg = JSON.parse(line); } catch { return; }

  if (msg.method === 'initialize') {
    send({
      jsonrpc: '2.0', id: msg.id,
      result: {
        protocolVersion: '2025-06-18',
        capabilities: { tools: {} },
        serverInfo: { name: 'minimal-mcp', version: '1.0.0' }
      }
    });
  } else if (msg.method === 'initialized') {
    // notification — no response
  } else if (msg.method === 'tools/list') {
    send({ jsonrpc: '2.0', id: msg.id, result: { tools: TOOLS } });
  } else if (msg.method === 'tools/call') {
    if (msg.params.name === 'get_timestamp') {
      send({
        jsonrpc: '2.0', id: msg.id,
        result: { content: [{ type: 'text', text: new Date().toISOString() }] }
      });
    }
  }
});

// Server responds to resources/list with:
{
  "resources": [
    {
      "uri": "file:///workspace/api-spec.yaml",
      "name": "API Specification",
      "mimeType": "application/yaml"
    },
    {
      "uri": "db://users/schema",
      "name": "Users Table Schema",
      "mimeType": "text/plain"
    }
  ]
}

// prompts/get response — server fills in the template
{
  "messages": [
    {
      "role": "user",
      "content": {
        "type": "text",
        "text": "Review the following code change for security vulnerabilities...\n\n{{code_diff}}"
      }
    }
  ]
}

# GitHub Actions CI workflow
- name: Generate MCP config
  run: |
    cat > /tmp/mcp-config.json << EOF
    {
      "mcpServers": {
        "github": {
          "command": "npx",
          "args": ["-y", "@github/mcp-server@2.1.0"],
          "env": { "GITHUB_TOKEN": "${{ secrets.CI_GITHUB_TOKEN }}" }
        }
      }
    }
    EOF

- name: Run Claude Code task
  run: claude --mcp-config /tmp/mcp-config.json -p "Create a PR summary for the latest diff"
